1	#ifndef VPR_DEVICE_ANNOTATION_H
2	#define VPR_DEVICE_ANNOTATION_H
3	
4	/********************************************************************
5	 * Include header files required by the data structure definition
6	 *******************************************************************/
7	#include <map>
