21	
22	/* Begin namespace openfpga */
23	namespace openfpga {
24	
25	/* Unique index for pb_graph node */
26	struct pb_graph_node_id_tag;
27	
28	typedef vtr::StrongId<pb_graph_node_id_tag> PbGraphNodeId;
29	
30	/********************************************************************
31	 * This is the critical data structure to link the pb_type in VPR
32	 * to openfpga annotations
33	 * With a given pb_type pointer, it aims to identify:
34	 * 1. if the pb_type is a physical pb_type or a operating pb_type
35	 * 2. what is the circuit model id linked to a physical pb_type
36	 * 3. what is the physical pb_type for an operating pb_type
37	 * 4. what is the mode pointer that represents the physical mode for a pb_type
38	 *******************************************************************/
39	class VprDeviceAnnotation {
40	 public: /* Constructor */
41	  VprDeviceAnnotation();
42	
43	 public: /* Public accessors */
44	  bool is_physical_pb_type(t_pb_type* pb_type) const;
45	  t_mode* physical_mode(t_pb_type* pb_type) const;
46	  t_pb_type* physical_pb_type(t_pb_type* pb_type) const;
47	  std::vector<t_port*> physical_pb_port(t_port* pb_port) const;
48	  BasicPort physical_pb_port_range(t_port* operating_pb_port,
49	                                   t_port* physical_pb_port) const;
50	  CircuitModelId pb_type_circuit_model(t_pb_type* physical_pb_type) const;
51	  CircuitModelId interconnect_circuit_model(
52	    t_interconnect* pb_interconnect) const;
53	  e_interconnect interconnect_physical_type(
54	    t_interconnect* pb_interconnect) const;
55	  CircuitPortId pb_circuit_port(t_port* pb_port) const;
56	  std::vector<char> pb_type_mode_bits(t_pb_type* pb_type) const;
57	  std::string pb_type_mode_bits_to_string(t_pb_type* pb_type) const;
58	
59	  /* Get the unique index of a pb_graph_node */
60	  PbGraphNodeId pb_graph_node_unique_index(
61	    t_pb_graph_node* pb_graph_node) const;
62	  /* Get the pointer to a pb_graph node using an unique index */
63	  t_pb_graph_node* pb_graph_node(t_pb_type* pb_type,
64	                                 const PbGraphNodeId& unique_index) const;
65	  t_pb_graph_node* physical_pb_graph_node(t_pb_graph_node* pb_graph_node) const;
66	  float physical_pb_type_index_factor(t_pb_type* pb_type) const;
67	  int physical_pb_type_index_offset(t_pb_type* pb_type) const;
68	
69	  int physical_pb_pin_initial_offset(t_port* operating_pb_port,
70	                                     t_port* physical_pb_port) const;
71	
72	  int physical_pb_pin_rotate_offset(t_port* operating_pb_port,
73	                                    t_port* physical_pb_port) const;
74	
75	  int physical_pb_port_rotate_offset(t_port* operating_pb_port,
76	                                     t_port* physical_pb_port) const;
77	
78	  /**This function returns an accumulated offset. Note that the
79	   * accumulated offset is NOT the pin rotate offset specified by users
80	   * It is an aggregation of the offset during pin pairing
81	   * Each time, we manage to pair two pins, the accumulated offset will be
82	   * incremented by the pin rotate offset value The accumulated offset will be
83	   * reset to 0 when it exceeds the msb() of the physical port
84	   */
85	  int physical_pb_pin_offset(t_port* operating_pb_port,
86	                             t_port* physical_pb_port) const;
87	  int physical_pb_port_offset(t_port* operating_pb_port,
88	                              t_port* physical_pb_port) const;
89	  t_pb_graph_pin* physical_pb_graph_pin(
90	    const t_pb_graph_pin* pb_graph_pin) const;
91	  CircuitModelId rr_switch_circuit_model(const RRSwitchId& rr_switch) const;
92	  CircuitModelId rr_segment_circuit_model(const RRSegmentId& rr_segment) const;
93	  ArchDirectId direct_annotation(const size_t& direct) const;
94	  LbRRGraph physical_lb_rr_graph(t_pb_graph_node* pb_graph_head) const;
95	  BasicPort physical_tile_pin_port_info(t_physical_tile_type_ptr physical_tile,
96	                                        const int& pin_index) const;
97	  int physical_tile_pin_subtile_index(t_physical_tile_type_ptr physical_tile,
98	                                      const int& pin_index) const;
99	  int physical_tile_z_to_subtile_index(t_physical_tile_type_ptr physical_tile,
100	                                       const int& subtile_z) const;
101	  int physical_tile_z_to_start_pin_index(t_physical_tile_type_ptr physical_tile,
102	                                         const int& subtile_z) const;
103	  t_logical_block_type_ptr physical_equivalent_site(
104	    t_physical_tile_type_ptr physical_tile,
105	    const std::string& sub_tile_name) const;
106	
107	 public: /* Public mutators */
108	  void add_pb_type_physical_mode(t_pb_type* pb_type, t_mode* physical_mode);
109	  void add_physical_pb_type(t_pb_type* operating_pb_type,
110	                            t_pb_type* physical_pb_type);
111	  void add_physical_pb_port(t_port* operating_pb_port,
112	                            t_port* physical_pb_port);
113	  void add_physical_pb_port_range(t_port* operating_pb_port,
114	                                  t_port* physical_pb_port,
115	                                  const BasicPort& port_range);
116	  void add_pb_type_circuit_model(t_pb_type* physical_pb_type,
117	                                 const CircuitModelId& circuit_model);
118	  void add_interconnect_circuit_model(t_interconnect* pb_interconnect,
119	                                      const CircuitModelId& circuit_model);
120	  void add_interconnect_physical_type(t_interconnect* pb_interconnect,
121	                                      const e_interconnect& physical_type);
122	  void add_pb_circuit_port(t_port* pb_port, const CircuitPortId& circuit_port);
123	  void add_pb_type_mode_bits(t_pb_type* pb_type,
124	                             const std::vector<char>& mode_bits,
125	                             const bool& verbose);
126	  void add_pb_graph_node_unique_index(t_pb_graph_node* pb_graph_node);
127	  void add_physical_pb_graph_node(t_pb_graph_node* operating_pb_graph_node,
128	                                  t_pb_graph_node* physical_pb_graph_node);
129	  void add_physical_pb_type_index_factor(t_pb_type* pb_type,
130	                                         const float& factor);
131	  void add_physical_pb_type_index_offset(t_pb_type* pb_type, const int& offset);
132	  void add_physical_pb_pin_initial_offset(t_port* operating_pb_port,
133	                                          t_port* physical_pb_port,
134	                                          const int& offset);
135	  void add_physical_pb_port_rotate_offset(t_port* operating_pb_port,
136	                                          t_port* physical_pb_port,
137	                                          const int& offset);
138	  void accumulate_physical_pb_port_rotate_offset(t_port* operating_pb_port,
139	                                                 t_port* physical_pb_port);
140	  void add_physical_pb_pin_rotate_offset(t_port* operating_pb_port,
141	                                         t_port* physical_pb_port,
142	                                         const int& offset);
143	  void add_physical_pb_graph_pin(const t_pb_graph_pin* operating_pb_graph_pin,
144	                                 t_pb_graph_pin* physical_pb_graph_pin);
145	  void add_rr_switch_circuit_model(const RRSwitchId& rr_switch,
146	                                   const CircuitModelId& circuit_model);
147	  void add_rr_segment_circuit_model(const RRSegmentId& rr_segment,
148	                                    const CircuitModelId& circuit_model);
149	  void add_direct_annotation(const size_t& direct,
150	                             const ArchDirectId& arch_direct_id);
151	  void add_physical_lb_rr_graph(t_pb_graph_node* pb_graph_head,
152	                                const LbRRGraph& lb_rr_graph);
153	  void add_physical_tile_pin2port_info_pair(
154	    t_physical_tile_type_ptr physical_tile, const int& pin_index,
155	    const BasicPort& port);
156	  void add_physical_tile_pin_subtile_index(
157	    t_physical_tile_type_ptr physical_tile, const int& pin_index,
158	    const int& subtile_index);
159	  void add_physical_tile_z_to_subtile_index(
160	    t_physical_tile_type_ptr physical_tile, const int& subtile_z,
161	    const int& subtile_index);
162	  void add_physical_tile_z_to_start_pin_index(
163	    t_physical_tile_type_ptr physical_tile, const int& subtile_z,
164	    const int& start_pin_index);
165	  void set_subtile_physical_equivalent_site(
166	    t_physical_tile_type_ptr physical_tile, const std::string& sub_tile_name,
167	    t_logical_block_type_ptr phy_site);
168	
169	 private: /* Internal data */
170	  /* Pair a regular pb_type to its physical pb_type */
171	  std::map<t_pb_type*, t_pb_type*> physical_pb_types_;
172	  std::map<t_pb_type*, float> physical_pb_type_index_factors_;
173	  std::map<t_pb_type*, int> physical_pb_type_index_offsets_;
174	
175	  /* Pair a physical mode for a pb_type
176	   * Note:
177	   * - the physical mode MUST be a child mode of the pb_type
178	   * - the pb_type MUST be a physical pb_type itself
179	   */
180	  std::map<t_pb_type*, t_mode*> physical_pb_modes_;
181	
182	  /* Pair a physical pb_type to its circuit model
183	   * Note:
184	   * - the pb_type MUST be a physical pb_type itself
185	   */
186	  std::map<t_pb_type*, CircuitModelId> pb_type_circuit_models_;
187	
188	  /* Pair a interconnect of a physical pb_type to its circuit model
189	   * Note:
190	   * - the pb_type MUST be a physical pb_type itself
191	   */
192	  std::map<t_interconnect*, CircuitModelId> interconnect_circuit_models_;
193	
194	  /* Physical type of interconnect
195	   * Note:
196	   * - only applicable to an interconnect belongs to physical mode
197	   */
198	  std::map<t_interconnect*, e_interconnect> interconnect_physical_types_;
199	
200	  /* Pair a pb_type to its mode selection bits
201	   * - if the pb_type is a physical pb_type, the mode bits are the default mode
202	   *   where the physical pb_type will operate when used
203	   * - if the pb_type is an operating pb_type, the mode bits will be applied
204	   *   when the operating pb_type is used by packer
205	   */
206	  std::map<t_pb_type*, std::vector<char>> pb_type_mode_bits_;
207	
208	  /* Pair a pb_port to its physical pb_port
209	   * Note:
210	   * - the parent of physical pb_port MUST be a physical pb_type
211	   */
212	  std::map<t_port*, std::vector<t_port*>> physical_pb_ports_;
213	  std::map<t_port*, std::map<t_port*, int>> physical_pb_pin_initial_offsets_;
214	  std::map<t_port*, std::map<t_port*, int>> physical_pb_pin_rotate_offsets_;
215	  std::map<t_port*, std::map<t_port*, int>> physical_pb_port_rotate_offsets_;
216	
217	  /* Accumulated offsets for a physical pb port, just for internal usage */
218	  std::map<t_port*, std::map<t_port*, int>> physical_pb_port_offsets_;
219	  /* Accumulated offsets for a physical pb_graph_pin, just for internal usage */
220	  std::map<t_port*, std::map<t_port*, int>> physical_pb_pin_offsets_;
221	
222	  /* Pair a pb_port to its LSB and MSB of a physical pb_port
223	   * Note:
224	   * - the LSB and MSB MUST be in range of the physical pb_port
225	   */
226	  std::map<t_port*, std::map<t_port*, BasicPort>> physical_pb_port_ranges_;
227	
228	  /* Pair a pb_port to a circuit port in circuit model
229	   * Note:
230	   * - the parent of physical pb_port MUST be a physical pb_type
231	   */
232	  std::map<t_port*, CircuitPortId> pb_circuit_ports_;
233	
234	  /* Pair each pb_graph_node to an unique index in the graph
235	   * The unique index if the index in the array of t_pb_graph_node*
236	   */
237	  std::map<t_pb_type*, std::vector<t_pb_graph_node*>>
238	    pb_graph_node_unique_index_;
239	
240	  /* Pair a pb_graph_node to a physical pb_graph_node
241	   * Note:
242	   * - the pb_type of physical pb_graph_node must be a physical pb_type
243	   */
244	  std::map<t_pb_graph_node*, t_pb_graph_node*> physical_pb_graph_nodes_;
245	
246	  /* Pair a pb_graph_pin to a physical pb_graph_pin */
247	  std::map<const t_pb_graph_pin*, t_pb_graph_pin*> physical_pb_graph_pins_;
248	
249	  /* Pair a Routing Resource Switch (rr_switch) to a circuit model */
250	  std::map<RRSwitchId, CircuitModelId> rr_switch_circuit_models_;
251	
252	  /* Pair a Routing Segment (rr_segment) to a circuit model */
253	  std::map<RRSegmentId, CircuitModelId> rr_segment_circuit_models_;
254	
255	  /* Pair a direct connection (direct) to a annotation which contains circuit
256	   * model id */
257	  std::map<size_t, ArchDirectId> direct_annotations_;
258	
259	  /* Logical type routing resource graphs built from physical modes */
260	  std::map<t_pb_graph_node*, LbRRGraph> physical_lb_rr_graphs_;
261	
262	  /* A fast look-up from pin index in physical tile to physical tile port */
263	  std::map<t_physical_tile_type_ptr, std::map<int, BasicPort>>
264	    physical_tile_pin2port_info_map_;
265	  /* A fast look-up from pin index in physical tile to sub tile index */
266	  std::map<t_physical_tile_type_ptr, std::map<int, int>>
267	    physical_tile_pin_subtile_indices_;
268	  /* A fast look-up from z (a valid instance index considering all the sub tiles
269	   * in a given physical tile) to the index in sub tile array The instance index
270	   * starts from 0 to the sum of the capacity of each sub tile
271	   */
272	  std::map<t_physical_tile_type_ptr, std::map<int, int>>
273	    physical_tile_z_to_subtile_indices_;
274	  /* A fast look-up from z (a valid instance index considering all the sub tiles
275	   * in a given physical tile) to the index of the first pin in a given physcial
276	   * tile The instance index starts from 0 to the sum of the capacity of each
277	   * sub tile
278	   */
279	  std::map<t_physical_tile_type_ptr, std::map<int, int>>
280	    physical_tile_z_to_start_pin_indices_;
281	  /* Physical equivalent sites */
282	  std::map<t_physical_tile_type_ptr,
283	           std::map<std::string, t_logical_block_type_ptr>>
284	    physical_equivalent_sites_;
285	};
286	
287	} /* End namespace openfpga*/
288	
289	#endif
