1	/********************************************************************
2	 * This file includes functions to build links between pb_types
3	 * in particular to annotate the physical mode and physical pb_type
4	 *******************************************************************/
5	/* Headers from vtrutil library */
6	#include "annotate_pb_types.h"
7	
8	#include "annotate_pb_graph.h"
9	#include "check_pb_type_annotation.h"
10	#include "pb_type_utils.h"
11	#include "vpr_device_annotation.h"
12	#include "vtr_assert.h"
13	#include "vtr_log.h"
14	#include "vtr_time.h"
15	
16	/* begin namespace openfpga */
17	namespace openfpga {
18	
19	/********************************************************************
20	 * This function will identify the physical mode for each multi-mode
21	 * pb_type in VPR pb_type graph by following the explicit definition
22	 * in OpenFPGA architecture XML
23	 *******************************************************************/
24	static void build_vpr_physical_pb_mode_explicit_annotation(
25	  const DeviceContext& vpr_device_ctx, const Arch& openfpga_arch,
26	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
27	  /* Walk through the pb_type annotation stored in the openfpga arch */
28	  for (const PbTypeAnnotation& pb_type_annotation :
29	       openfpga_arch.pb_type_annotations) {
30	    /* Since our target is to annotate the physical mode name,
31	     * we can skip those has not physical mode defined
32	     */
33	    if (true == pb_type_annotation.physical_mode_name().empty()) {
34	      continue;
35	    }
36	
37	    /* Identify if the pb_type is operating or physical,
38	     * For operating pb_type, get the full name of operating pb_type
39	     * For physical pb_type, get the full name of physical pb_type
40	     */
41	    std::vector<std::string> target_pb_type_names;
42	    std::vector<std::string> target_pb_mode_names;
43	
44	    if (true == pb_type_annotation.is_operating_pb_type()) {
45	      target_pb_type_names =
46	        pb_type_annotation.operating_parent_pb_type_names();
47	      target_pb_type_names.push_back(
48	        pb_type_annotation.operating_pb_type_name());
49	      target_pb_mode_names = pb_type_annotation.operating_parent_mode_names();
50	    }
51	
52	    if (true == pb_type_annotation.is_physical_pb_type()) {
53	      target_pb_type_names = pb_type_annotation.physical_parent_pb_type_names();
54	      target_pb_type_names.push_back(
55	        pb_type_annotation.physical_pb_type_name());
56	      target_pb_mode_names = pb_type_annotation.physical_parent_mode_names();
57	    }
58	
59	    /* We must have at least one pb_type in the list */
60	    VTR_ASSERT_SAFE(0 < target_pb_type_names.size());
61	
62	    /* Pb type information are located at the logic_block_types in the device
63	     * context of VPR We iterate over the vectors and find the pb_type matches
64	     * the parent_pb_type_name
65	     */
66	    bool link_success = false;
67	
68	    for (const t_logical_block_type& lb_type :
69	         vpr_device_ctx.logical_block_types) {
70	      /* By pass nullptr for pb_type head */
71	      if (nullptr == lb_type.pb_type) {
72	        continue;
73	      }
74	      /* Check the name of the top-level pb_type, if it does not match, we can
75	       * bypass */
76	      if (target_pb_type_names[0] != std::string(lb_type.pb_type->name)) {
77	        continue;
78	      }
79	      /* Match the name in the top-level, we go further to search the pb_type in
80	       * the graph */
81	      t_pb_type* target_pb_type = try_find_pb_type_with_given_path(
82	        lb_type.pb_type, target_pb_type_names, target_pb_mode_names);
83	      if (nullptr == target_pb_type) {
84	        continue;
85	      }
86	
87	      /* Found, we update the annotation by assigning the physical mode */
88	      t_mode* physical_mode = find_pb_type_mode(
89	        target_pb_type, pb_type_annotation.physical_mode_name().c_str());
90	      vpr_device_annotation.add_pb_type_physical_mode(target_pb_type,
91	                                                      physical_mode);
92	
93	      /* Give a message */
94	      VTR_LOGV(verbose_output,
95	               "Annotate pb_type '%s' with physical mode '%s'\n",
96	               target_pb_type->name, physical_mode->name);
97	
98	      link_success = true;
99	      break;
100	    }
101	
102	    if (false == link_success) {
103	      /* Not found, error out! */
104	      VTR_LOG_ERROR(
105	        "Unable to find the pb_type '%s' in VPR architecture definition!\n",
106	        target_pb_type_names.back().c_str());
107	      return;
108	    }
109	  }
110	}
111	
112	/********************************************************************
113	 * This function will recursively visit all the pb_type from the top
114	 * pb_type in the graph and
115	 * infer the physical mode for each multi-mode
116	 * pb_type in VPR pb_type graph without OpenFPGA architecture XML
117	 *
118	 * The following rule is applied:
119	 * if there is only 1 mode under a pb_type, it will be the default
120	 * physical mode for this pb_type
121	 *******************************************************************/
122	static void rec_infer_vpr_physical_pb_mode_annotation(
123	  t_pb_type* cur_pb_type, VprDeviceAnnotation& vpr_device_annotation,
124	  const bool& verbose_output) {
125	  /* We do not check any primitive pb_type */
126	  if (true == is_primitive_pb_type(cur_pb_type)) {
127	    return;
128	  }
129	
130	  /* For non-primitive pb_type:
131	   * - if there is only one mode, it will be the physical mode
132	   *   we just need to make sure that we do not repeatedly annotate this
133	   * - if there are multiple modes, we should be able to find a physical mode
134	   *   and then go recursively
135	   */
136	  t_mode* physical_mode = nullptr;
137	
138	  if (1 == cur_pb_type->num_modes) {
139	    if (nullptr == vpr_device_annotation.physical_mode(cur_pb_type)) {
140	      /* Not assigned by explicit annotation, we should infer here */
141	      vpr_device_annotation.add_pb_type_physical_mode(cur_pb_type,
142	                                                      &(cur_pb_type->modes[0]));
143	      VTR_LOGV(verbose_output,
144	               "Implicitly infer physical mode '%s' for pb_type '%s'\n",
145	               cur_pb_type->modes[0].name, cur_pb_type->name);
146	    }
147	  } else {
148	    VTR_ASSERT(1 < cur_pb_type->num_modes);
149	    if (nullptr == vpr_device_annotation.physical_mode(cur_pb_type)) {
150	      /* Not assigned by explicit annotation, we should infer here */
151	      vpr_device_annotation.add_pb_type_physical_mode(cur_pb_type,
152	                                                      &(cur_pb_type->modes[0]));
153	      VTR_LOG_ERROR(
154	        "Unable to find a physical mode for a multi-mode pb_type '%s'!\n",
155	        cur_pb_type->name);
156	      VTR_LOG_ERROR("Please specify in the OpenFPGA architecture\n");
157	      return;
158	    }
159	  }
160	
161	  /* Get the physical mode from annotation */
162	  physical_mode = vpr_device_annotation.physical_mode(cur_pb_type);
163	
164	  VTR_ASSERT(nullptr != physical_mode);
165	
166	  /* Traverse the pb_type children under the physical mode */
167	  for (int ichild = 0; ichild < physical_mode->num_pb_type_children; ++ichild) {
168	    rec_infer_vpr_physical_pb_mode_annotation(
169	      &(physical_mode->pb_type_children[ichild]), vpr_device_annotation,
170	      verbose_output);
171	  }
