200	/********************************************************************
201	 * This function aims to make a pair of operating and physical
202	 * pb_types:
203	 * - In addition to pairing the pb_types, it will pair the ports of the pb_types
204	 * - For the ports which are explicited annotated as physical pin mapping
205	 *   in the pb_type annotation.
206	 *   We will check the port range and create a pair
207	 * - For the ports which are not specified in the pb_type annotation
208	 *   we assume their physical ports share the same as the operating ports
209	 *   We will try to find a port in the physical pb_type and check the port range
210	 *   If found, we will create a pair
211	 * - All the pairs will be updated in vpr_device_annotation
212	 *******************************************************************/
213	static bool pair_operating_and_physical_pb_types(
214	  t_pb_type* operating_pb_type, t_pb_type* physical_pb_type,
215	  const PbTypeAnnotation& pb_type_annotation,
216	  VprDeviceAnnotation& vpr_device_annotation) {
217	  /* Reach here, we should have valid operating and physical pb_types */
218	  VTR_ASSERT((nullptr != operating_pb_type) && (nullptr != physical_pb_type));
219	
220	  /* Iterate over the ports under the operating pb_type
221	   * For each pin, we will try to find its physical port in the
222	   * pb_type_annotation if not found, we assume that the physical port is the
223	   * same as the operating pb_port
224	   */
225	  for (t_port* operating_pb_port : pb_type_ports(operating_pb_type)) {
226	    std::map<BasicPort, std::array<int, 3>> expected_physical_pb_ports =
227	      pb_type_annotation.physical_pb_type_port(
228	        std::string(operating_pb_port->name));
229	
230	    /* If not defined in the annotation, set the default pair:
231	     * rotate_offset is 0 by default!
232	     */
233	    if (true == expected_physical_pb_ports.empty()) {
234	      BasicPort expected_physical_pb_port;
235	      expected_physical_pb_port.set_name(std::string(operating_pb_port->name));
236	      expected_physical_pb_port.set_width(operating_pb_port->num_pins);
237	      expected_physical_pb_ports[expected_physical_pb_port] = {0, 0};
238	    }
239	
240	    for (const auto& expected_physical_pb_port : expected_physical_pb_ports) {
241	      /* Try to find the expected port in the physical pb_type */
242	      t_port* physical_pb_port = find_pb_type_port(
243	        physical_pb_type, expected_physical_pb_port.first.get_name());
244	      /* Not found, mapping fails */
245	      if (nullptr == physical_pb_port) {
246	        return false;
247	      }
248	      /* If the port range does not match, mapping fails */
249	      if (false == BasicPort(physical_pb_port->name, physical_pb_port->num_pins)
250	                     .contained(expected_physical_pb_port.first)) {
251	        return false;
252	      }
253	      /* Now, port mapping should succeed, we update the vpr_device_annotation
254	       * - port binding
255	       * - port range
256	       * - port pin rotate offset
257	       */
258	      vpr_device_annotation.add_physical_pb_port(operating_pb_port,
259	                                                 physical_pb_port);
260	      vpr_device_annotation.add_physical_pb_port_range(
261	        operating_pb_port, physical_pb_port, expected_physical_pb_port.first);
262	      vpr_device_annotation.add_physical_pb_pin_initial_offset(
263	        operating_pb_port, physical_pb_port,
264	        expected_physical_pb_port.second[0]);
265	      vpr_device_annotation.add_physical_pb_pin_rotate_offset(
266	        operating_pb_port, physical_pb_port,
267	        expected_physical_pb_port.second[1]);
268	      vpr_device_annotation.add_physical_pb_port_rotate_offset(
269	        operating_pb_port, physical_pb_port,
270	        expected_physical_pb_port.second[2]);
271	    }
272	  }
273	
274	  /* Now, pb_type mapping should succeed, we update the vpr_device_annotation
275	   *   - pb_type binding
276	   *   - physical_pb_type_index_factor
277	   *   - physical_pb_type_index_offset
278	   */
279	  vpr_device_annotation.add_physical_pb_type(operating_pb_type,
280	                                             physical_pb_type);
281	  vpr_device_annotation.add_physical_pb_type_index_factor(
282	    operating_pb_type, pb_type_annotation.physical_pb_type_index_factor());
283	  vpr_device_annotation.add_physical_pb_type_index_offset(
284	    operating_pb_type, pb_type_annotation.physical_pb_type_index_offset());
285	
286	  return true;
287	}
