289	/********************************************************************
290	 * This function will identify the physical pb_type for each operating
291	 * pb_type in VPR pb_type graph by following the explicit definition
292	 * in OpenFPGA architecture XML
293	 *
294	 * Note:
295	 * - This function should be executed only AFTER the physical mode
296	 *   annotation is completed
297	 *******************************************************************/
298	static void build_vpr_physical_pb_type_explicit_annotation(
299	  const DeviceContext& vpr_device_ctx, const Arch& openfpga_arch,
300	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
301	  /* Walk through the pb_type annotation stored in the openfpga arch */
302	  for (const PbTypeAnnotation& pb_type_annotation :
303	       openfpga_arch.pb_type_annotations) {
304	    /* Since our target is to annotate the operating pb_type tp physical pb_type
305	     * we can skip those annotation only for physical pb_type
306	     */
307	    if (true == pb_type_annotation.is_physical_pb_type()) {
308	      continue;
309	    }
310	
311	    VTR_ASSERT(true == pb_type_annotation.is_operating_pb_type());
312	
313	    /* Collect the information about the full hierarchy of operating pb_type to
314	     * be annotated */
315	    std::vector<std::string> target_op_pb_type_names;
316	    std::vector<std::string> target_op_pb_mode_names;
317	
318	    target_op_pb_type_names =
319	      pb_type_annotation.operating_parent_pb_type_names();
320	    target_op_pb_type_names.push_back(
321	      pb_type_annotation.operating_pb_type_name());
322	    target_op_pb_mode_names = pb_type_annotation.operating_parent_mode_names();
323	
324	    /* Collect the information about the full hierarchy of physical pb_type to
325	     * be annotated */
326	    std::vector<std::string> target_phy_pb_type_names;
327	    std::vector<std::string> target_phy_pb_mode_names;
328	
329	    target_phy_pb_type_names =
330	      pb_type_annotation.physical_parent_pb_type_names();
331	    target_phy_pb_type_names.push_back(
332	      pb_type_annotation.physical_pb_type_name());
333	    target_phy_pb_mode_names = pb_type_annotation.physical_parent_mode_names();
334	
335	    /* We must have at least one pb_type in the list */
336	    VTR_ASSERT_SAFE(0 < target_op_pb_type_names.size());
337	    VTR_ASSERT_SAFE(0 < target_phy_pb_type_names.size());
338	
339	    /* Pb type information are located at the logic_block_types in the device
340	     * context of VPR We iterate over the vectors and find the pb_type matches
341	     * the parent_pb_type_name
342	     */
343	    bool link_success = false;
344	
345	    for (const t_logical_block_type& lb_type :
346	         vpr_device_ctx.logical_block_types) {
347	      /* By pass nullptr for pb_type head */
348	      if (nullptr == lb_type.pb_type) {
349	        continue;
350	      }
351	      /* Check the name of the top-level pb_type, if it does not match, we can
352	       * bypass */
353	      if (target_op_pb_type_names[0] != std::string(lb_type.pb_type->name)) {
354	        continue;
355	      }
356	      /* Match the name in the top-level, we go further to search the operating
357	       * as well as physical pb_types in the graph */
358	      t_pb_type* target_op_pb_type = try_find_pb_type_with_given_path(
359	        lb_type.pb_type, target_op_pb_type_names, target_op_pb_mode_names);
360	      if (nullptr == target_op_pb_type) {
361	        continue;
362	      }
363	
364	      t_pb_type* target_phy_pb_type = try_find_pb_type_with_given_path(
365	        lb_type.pb_type, target_phy_pb_type_names, target_phy_pb_mode_names);
366	      if (nullptr == target_phy_pb_type) {
367	        continue;
368	      }
369	
370	      /* Both operating and physical pb_type have been found,
371	       * we update the annotation by assigning the physical mode
372	       */
373	      if (true == pair_operating_and_physical_pb_types(
374	                    target_op_pb_type, target_phy_pb_type, pb_type_annotation,
375	                    vpr_device_annotation)) {
376	        /* Give a message */
377	        VTR_LOGV(
378	          verbose_output,
379	          "Annotate operating pb_type '%s' to its physical pb_type '%s'\n",
380	          target_op_pb_type->name, target_phy_pb_type->name);
381	
382	        link_success = true;
383	        break;
384	      }
385	    }
386	
387	    if (false == link_success) {
388	      /* Not found, error out! */
389	      VTR_LOG_ERROR(
390	        "Unable to pair the operating pb_type '%s' to its physical pb_type "
391	        "'%s'!\n",
392	        target_op_pb_type_names.back().c_str(),
393	        target_phy_pb_type_names.back().c_str());
394	    }
395	  }
396	}
