398	/********************************************************************
399	 * This function aims to pair a physical pb_type to itself
400	 *******************************************************************/
401	static bool self_pair_physical_pb_types(
402	  t_pb_type* physical_pb_type, VprDeviceAnnotation& vpr_device_annotation) {
403	  /* Reach here, we should have valid physical pb_types */
404	  VTR_ASSERT(nullptr != physical_pb_type);
405	
406	  /* Iterate over the ports under the operating pb_type
407	   * For each pin, we will try to find its physical port in the
408	   * pb_type_annotation if not found, we assume that the physical port is the
409	   * same as the operating pb_port
410	   */
411	  for (t_port* physical_pb_port : pb_type_ports(physical_pb_type)) {
412	    BasicPort physical_port_range(physical_pb_port->name,
413	                                  physical_pb_port->num_pins);
414	    vpr_device_annotation.add_physical_pb_port(physical_pb_port,
415	                                               physical_pb_port);
416	    vpr_device_annotation.add_physical_pb_port_range(
417	      physical_pb_port, physical_pb_port, physical_port_range);
418	  }
419	
420	  /* Now, pb_type mapping should succeed, we update the vpr_device_annotation */
421	  vpr_device_annotation.add_physical_pb_type(physical_pb_type,
422	                                             physical_pb_type);
423	
424	  return true;
425	}
