427	/********************************************************************
428	 * This function will recursively visit all the pb_type from the top
429	 * pb_type in the graph (only in the physical mode) and infer the
430	 * physical pb_type
431	 * This is mainly applied to single-mode pb_type graphs, where the
432	 * physical pb_type should be pb_type itself
433	 * We can infer this and save the explicit annotation required by users
434	 *******************************************************************/
435	static void rec_infer_vpr_physical_pb_type_annotation(
436	  t_pb_type* cur_pb_type, VprDeviceAnnotation& vpr_device_annotation,
437	  const bool& verbose_output) {
438	  /* Physical pb_type is mainly for the primitive pb_type */
439	  if (true == is_primitive_pb_type(cur_pb_type)) {
440	    /* If the physical pb_type has been mapped, we can skip it */
441	    if (nullptr != vpr_device_annotation.physical_pb_type(cur_pb_type)) {
442	      return;
443	    }
444	    /* Create the pair here */
445	    if (true ==
446	        self_pair_physical_pb_types(cur_pb_type, vpr_device_annotation)) {
447	      /* Give a message */
448	      VTR_LOGV(
449	        verbose_output,
450	        "Implicitly infer the physical pb_type for pb_type '%s' itself\n",
451	        cur_pb_type->name);
452	    } else {
453	      VTR_LOG_ERROR(
454	        "Unable to infer the physical pb_type for pb_type '%s' itself!\n",
455	        cur_pb_type->name);
456	    }
457	    return;
458	  }
459	
460	  /* Get the physical mode from annotation */
461	  t_mode* physical_mode = vpr_device_annotation.physical_mode(cur_pb_type);
462	
463	  VTR_ASSERT(nullptr != physical_mode);
464	
465	  /* Traverse the pb_type children under the physical mode */
466	  for (int ichild = 0; ichild < physical_mode->num_pb_type_children; ++ichild) {
467	    rec_infer_vpr_physical_pb_type_annotation(
468	      &(physical_mode->pb_type_children[ichild]), vpr_device_annotation,
469	      verbose_output);
470	  }
471	}
