496	/********************************************************************
497	 * This function aims to link all the ports defined under a physical
498	 * pb_type to the ports of circuit model in the circuit library
499	 * The binding assumes that pb_type port should be defined with the same name
500	 * as the circuit port
501	 *******************************************************************/
502	static bool link_physical_pb_port_to_circuit_port(
503	  t_pb_type* physical_pb_type, const CircuitLibrary& circuit_lib,
504	  const CircuitModelId& circuit_model,
505	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
506	  bool link_success = true;
507	  /* Iterate over the pb_ports
508	   * Note:
509	   *   - Not every port defined in the circuit model will appear under the
510	   * pb_type Some circuit ports are just for physical implementation
511	   */
512	  for (t_port* pb_port : pb_type_ports(physical_pb_type)) {
513	    CircuitPortId circuit_port =
514	      circuit_lib.model_port(circuit_model, std::string(pb_port->name));
515	
516	    /* If we cannot find a port with the same name, error out */
517	    if (CircuitPortId::INVALID() == circuit_port) {
518	      VTR_LOG_ERROR(
519	        "Pb type port '%s' is not found in any port of circuit model '%s'!\n",
520	        pb_port->name, circuit_lib.model_name(circuit_model).c_str());
521	      link_success = false;
522	      continue;
523	    }
524	
525	    /* If the port width does not match, error out */
526	    if ((size_t)(pb_port->num_pins) != circuit_lib.port_size(circuit_port)) {
527	      VTR_LOG_ERROR(
528	        "Pb type port '%s[%d:%d]' does not match the port '%s[%d:%d]' of "
529	        "circuit model '%s' in size!\n",
530	        pb_port->name, 0, pb_port->num_pins - 1,
531	        circuit_lib.port_prefix(circuit_port).c_str(), 0,
532	        circuit_lib.port_size(circuit_port) - 1,
533	        circuit_lib.model_name(circuit_model).c_str());
534	      link_success = false;
535	      continue;
536	    }
537	
538	    /* If the port type does not match, error out */
539	    if (ERR_PORT == circuit_port_require_pb_port_type(
540	                      circuit_lib.port_type(circuit_port))) {
541	      VTR_LOG_ERROR(
542	        "Pb type port '%s' type does not match the port type '%s' of circuit "
543	        "model '%s'!\n",
544	        pb_port->name, circuit_lib.port_prefix(circuit_port).c_str(),
545	        circuit_lib.model_name(circuit_model).c_str());
546	
547	      link_success = false;
548	      continue;
549	    }
550	
551	    /* Reach here, it means that mapping should be ok, update the
552	     * vpr_device_annotation */
553	    vpr_device_annotation.add_pb_circuit_port(pb_port, circuit_port);
554	    VTR_LOGV(verbose_output,
555	             "Bind pb type '%s' port '%s' to circuit model '%s' port '%s'\n",
556	             physical_pb_type->name, pb_port->name,
557	             circuit_lib.model_name(circuit_model).c_str(),
558	             circuit_lib.port_prefix(circuit_port).c_str());
559	  }
560	
561	  return link_success;
562	}
