564	/********************************************************************
565	 * This function aims to link a physical pb_type to a valid circuit model
566	 * in the circuit library
567	 *******************************************************************/
568	static bool link_physical_pb_type_to_circuit_model(
569	  t_pb_type* physical_pb_type, const CircuitLibrary& circuit_lib,
570	  const PbTypeAnnotation& pb_type_annotation,
571	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
572	  /* Reach here, we should have valid operating and physical pb_types */
573	  VTR_ASSERT(nullptr != physical_pb_type);
574	
575	  /* This must be a physical pb_type according to our annotation! */
576	  if (false == vpr_device_annotation.is_physical_pb_type(physical_pb_type)) {
577	    VTR_LOG_ERROR(
578	      "An operating pb_type '%s' is not allowed to be linked to any circuit "
579	      "model!\n",
580	      physical_pb_type->name);
581	    return false;
582	  }
583	
584	  std::string pb_type_circuit_model_name =
585	    pb_type_annotation.circuit_model_name();
586	  CircuitModelId circuit_model_id =
587	    circuit_lib.model(pb_type_circuit_model_name);
588	
589	  if (CircuitModelId::INVALID() == circuit_model_id) {
590	    VTR_LOG_ERROR(
591	      "Unable to find a circuit model '%s' for physical pb_type '%s'!\n",
592	      pb_type_circuit_model_name.c_str(), physical_pb_type->name);
593	    return false;
594	  }
595	
596	  /* Ensure that the pb_type ports can be matched in the circuit model ports */
597	  if (false == link_physical_pb_port_to_circuit_port(
598	                 physical_pb_type, circuit_lib, circuit_model_id,
599	                 vpr_device_annotation, verbose_output)) {
600	    return false;
601	  }
602	
603	  /* Now the circuit model is valid, update the vpr_device_annotation */
604	  vpr_device_annotation.add_pb_type_circuit_model(physical_pb_type,
605	                                                  circuit_model_id);
606	  return true;
607	}
