609	/********************************************************************
610	 * This function aims to link an interconnect of a physical mode of
611	 * a pb_type to a valid circuit model in the circuit library
612	 *******************************************************************/
613	static bool link_physical_pb_interconnect_to_circuit_model(
614	  t_pb_type* physical_pb_type, const std::string& interconnect_name,
615	  const CircuitLibrary& circuit_lib, const PbTypeAnnotation& pb_type_annotation,
616	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
617	  /* The physical pb_type should NOT be a primitive, otherwise it should never
618	   * contain any interconnect */
619	  if (true == is_primitive_pb_type(physical_pb_type)) {
620	    VTR_LOG_ERROR(
621	      "Link interconnect to circuit model is not allowed for a primitive "
622	      "pb_type '%s'!\n",
623	      physical_pb_type->name);
624	    return false;
625	  }
626	
627	  /* Get the physical mode from annotation */
628	  t_mode* physical_mode = vpr_device_annotation.physical_mode(physical_pb_type);
629	
630	  VTR_ASSERT(nullptr != physical_mode);
631	
632	  /* Find the interconnect name under the physical mode of a physical pb_type */
633	  t_interconnect* pb_interc =
634	    find_pb_mode_interconnect(physical_mode, interconnect_name.c_str());
635	
636	  if (nullptr == pb_interc) {
637	    VTR_LOG_ERROR(
638	      "Unable to find interconnect '%s' under physical mode '%s' of pb_type "
639	      "'%s'!\n",
640	      interconnect_name.c_str(), physical_mode->name, physical_pb_type->name);
641	    return false;
642	  }
643	
644	  /* Try to find the circuit model name */
645	  std::string pb_type_circuit_model_name =
646	    pb_type_annotation.interconnect_circuit_model_name(interconnect_name);
647	  CircuitModelId circuit_model_id =
648	    circuit_lib.model(pb_type_circuit_model_name);
649	
650	  if (CircuitModelId::INVALID() == circuit_model_id) {
651	    VTR_LOG_ERROR(
652	      "Unable to find a circuit model '%s' for interconnect '%s' under "
653	      "physical mode '%s' of pb_type '%s'!\n",
654	      pb_type_circuit_model_name.c_str(), interconnect_name.c_str(),
655	      physical_mode->name, physical_pb_type->name);
656	    return false;
657	  }
658	
659	  /* Double check the type of circuit model, it should be the same as required
660	   * physical type */
661	  e_circuit_model_type required_circuit_model_type =
662	    pb_interconnect_require_circuit_model_type(
663	      vpr_device_annotation.interconnect_physical_type(pb_interc));
664	  if (circuit_lib.model_type(circuit_model_id) != required_circuit_model_type) {
665	    VTR_LOG_ERROR(
666	      "Circuit model '%s' type '%s' does not match required type '%s' for "
667	      "interconnect '%s' under physical mode '%s' of pb_type '%s'!\n",
668	      circuit_lib.model_name(circuit_model_id).c_str(),
669	      CIRCUIT_MODEL_TYPE_STRING[circuit_lib.model_type(circuit_model_id)],
670	      CIRCUIT_MODEL_TYPE_STRING[required_circuit_model_type],
671	      pb_interc->name.c_str(), physical_mode->name, physical_pb_type->name);
672	    return false;
673	  }
674	
675	  /* Now the circuit model is valid, update the vpr_device_annotation */
676	  vpr_device_annotation.add_interconnect_circuit_model(pb_interc,
677	                                                       circuit_model_id);
678	
679	  VTR_LOGV(verbose_output,
680	           "Bind pb_type '%s' physical mode '%s' interconnect '%s' to circuit "
681	           "model '%s'\n",
682	           physical_pb_type->name, physical_mode->name, pb_interc->name.c_str(),
683	           circuit_lib.model_name(circuit_model_id).c_str());
684	
685	  return true;
686	}
