696	 *******************************************************************/
697	static void link_vpr_pb_type_to_circuit_model_explicit_annotation(
698	  const DeviceContext& vpr_device_ctx, const Arch& openfpga_arch,
699	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
700	  /* Walk through the pb_type annotation stored in the openfpga arch */
701	  for (const PbTypeAnnotation& pb_type_annotation :
702	       openfpga_arch.pb_type_annotations) {
703	    /* Since our target is to annotate the circuti model for physical pb_type
704	     * we can skip those annotation only for operating pb_type
705	     */
706	    if (true == pb_type_annotation.is_operating_pb_type()) {
707	      continue;
708	    }
709	
710	    if (true == pb_type_annotation.circuit_model_name().empty()) {
711	      continue;
712	    }
713	
714	    VTR_ASSERT(true == pb_type_annotation.is_physical_pb_type());
715	
716	    /* Collect the information about the full hierarchy of physical pb_type to
717	     * be annotated */
718	    std::vector<std::string> target_phy_pb_type_names;
719	    std::vector<std::string> target_phy_pb_mode_names;
720	
721	    target_phy_pb_type_names =
722	      pb_type_annotation.physical_parent_pb_type_names();
723	    target_phy_pb_type_names.push_back(
724	      pb_type_annotation.physical_pb_type_name());
725	    target_phy_pb_mode_names = pb_type_annotation.physical_parent_mode_names();
726	
727	    /* We must have at least one pb_type in the list */
728	    VTR_ASSERT_SAFE(0 < target_phy_pb_type_names.size());
729	
730	    /* Pb type information are located at the logic_block_types in the device
731	     * context of VPR We iterate over the vectors and find the pb_type matches
732	     * the parent_pb_type_name
733	     */
734	    bool link_success = false;
735	
736	    for (const t_logical_block_type& lb_type :
737	         vpr_device_ctx.logical_block_types) {
738	      /* By pass nullptr for pb_type head */
739	      if (nullptr == lb_type.pb_type) {
740	        continue;
741	      }
742	      /* Check the name of the top-level pb_type, if it does not match, we can
743	       * bypass */
744	      if (target_phy_pb_type_names[0] != std::string(lb_type.pb_type->name)) {
745	        continue;
746	      }
747	      /* Match the name in the top-level, we go further to search the operating
748	       * as well as physical pb_types in the graph */
749	      t_pb_type* target_phy_pb_type = try_find_pb_type_with_given_path(
750	        lb_type.pb_type, target_phy_pb_type_names, target_phy_pb_mode_names);
751	      if (nullptr == target_phy_pb_type) {
752	        continue;
753	      }
754	
755	      /* Only try to bind pb_type to circuit model when it is defined by users
756	       */
757	      if (true == link_physical_pb_type_to_circuit_model(
758	                    target_phy_pb_type, openfpga_arch.circuit_lib,
759	                    pb_type_annotation, vpr_device_annotation,
760	                    verbose_output)) {
761	        /* Give a message */
762	        VTR_LOGV(verbose_output,
763	                 "Bind physical pb_type '%s' to its circuit model '%s'\n",
764	                 target_phy_pb_type->name,
765	                 openfpga_arch.circuit_lib
766	                   .model_name(vpr_device_annotation.pb_type_circuit_model(
767	                     target_phy_pb_type))
768	                   .c_str());
769	
770	        link_success = true;
771	        break;
772	      }
773	    }
774	
775	    if (false == link_success) {
776	      /* Not found, error out! */
777	      VTR_LOG_ERROR(
778	        "Unable to bind physical pb_type '%s' to circuit model '%s'!\n",
779	        target_phy_pb_type_names.back().c_str(),
780	        pb_type_annotation.circuit_model_name().c_str());
781	      return;
782	    }
783	  }
784	}
