795	static void link_vpr_pb_interconnect_to_circuit_model_explicit_annotation(
796	  const DeviceContext& vpr_device_ctx, const Arch& openfpga_arch,
797	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
798	  /* Walk through the pb_type annotation stored in the openfpga arch */
799	  for (const PbTypeAnnotation& pb_type_annotation :
800	       openfpga_arch.pb_type_annotations) {
801	    /* Since our target is to annotate the circuti model for physical pb_type
802	     * we can skip those annotation only for operating pb_type
803	     */
804	    if (true == pb_type_annotation.is_operating_pb_type()) {
805	      continue;
806	    }
807	
808	    if (0 == pb_type_annotation.interconnect_names().size()) {
809	      continue;
810	    }
811	
812	    VTR_ASSERT(true == pb_type_annotation.is_physical_pb_type());
813	
814	    /* Collect the information about the full hierarchy of physical pb_type to
815	     * be annotated */
816	    std::vector<std::string> target_phy_pb_type_names;
817	    std::vector<std::string> target_phy_pb_mode_names;
818	
819	    target_phy_pb_type_names =
820	      pb_type_annotation.physical_parent_pb_type_names();
821	    target_phy_pb_type_names.push_back(
822	      pb_type_annotation.physical_pb_type_name());
823	    target_phy_pb_mode_names = pb_type_annotation.physical_parent_mode_names();
824	
825	    /* We must have at least one pb_type in the list */
826	    VTR_ASSERT_SAFE(0 < target_phy_pb_type_names.size());
827	
828	    /* Pb type information are located at the logic_block_types in the device
829	     * context of VPR We iterate over the vectors and find the pb_type matches
830	     * the parent_pb_type_name
831	     */
832	    bool link_success = true;
833	
834	    for (const t_logical_block_type& lb_type :
835	         vpr_device_ctx.logical_block_types) {
836	      /* By pass nullptr for pb_type head */
837	      if (nullptr == lb_type.pb_type) {
838	        continue;
839	      }
840	      /* Check the name of the top-level pb_type, if it does not match, we can
841	       * bypass */
842	      if (target_phy_pb_type_names[0] != std::string(lb_type.pb_type->name)) {
843	        continue;
844	      }
845	      /* Match the name in the top-level, we go further to search the operating
846	       * as well as physical pb_types in the graph */
847	      t_pb_type* target_phy_pb_type = try_find_pb_type_with_given_path(
848	        lb_type.pb_type, target_phy_pb_type_names, target_phy_pb_mode_names);
849	      if (nullptr == target_phy_pb_type) {
850	        continue;
851	      }
852	
853	      /* Only try to bind interconnect to circuit model when it is defined by
854	       * users */
855	      for (const std::string& interc_name :
856	           pb_type_annotation.interconnect_names()) {
857	        if (false == link_physical_pb_interconnect_to_circuit_model(
858	                       target_phy_pb_type, interc_name,
859	                       openfpga_arch.circuit_lib, pb_type_annotation,
860	                       vpr_device_annotation, verbose_output)) {
861	          VTR_LOG_ERROR(
862	            "Unable to bind pb_type '%s' interconnect '%s' to circuit model "
863	            "'%s'!\n",
864	            target_phy_pb_type_names.back().c_str(), interc_name.c_str(),
865	            pb_type_annotation.circuit_model_name().c_str());
866	          link_success = false;
867	        }
868	      }
869	    }
870	
871	    if (false == link_success) {
872	      /* Not found, error out! */
873	      VTR_LOG_ERROR(
874	        "Unable to bind interconnects of physical pb_type '%s' to circuit "
875	        "model '%s'!\n",
876	        target_phy_pb_type_names.back().c_str(),
877	        pb_type_annotation.circuit_model_name().c_str());
878	      return;
879	    }
880	  }
881	}
