883	/********************************************************************
884	 * This function will recursively visit all the pb_type from the top
885	 * pb_type in the graph and infer the circuit model for physical mode
886	 * of pb_types in VPR pb_type graph without OpenFPGA architecture XML
887	 *
888	 * Because only the interconnect in physical modes need circuit model
889	 * annotation, we will skip all the operating modes here
890	 *
891	 * Note:
892	 *   - This function will automatically infer the type of circuit model
893	 *     that is required and find the default circuit model in the type
894	 *   - Interconnect type to Circuit mode type assumption:
895	 *     - MUX_INTERC -> CIRCUIT_MODEL_MUX
896	 *     - DIRECT_INTERC -> CIRCUIT_MODEL_WIRE
897	 *     - COMPLETE_INTERC (single input) -> CIRCUIT_MODEL_WIRE
898	 *     - COMPLETE_INTERC (multiple input pins) -> CIRCUIT_MODEL_MUX
899	 *******************************************************************/
900	static void rec_infer_vpr_pb_interconnect_circuit_model_annotation(
901	  t_pb_type* cur_pb_type, const CircuitLibrary& circuit_lib,
902	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
903	  /* We do not check any primitive pb_type */
904	  if (true == is_primitive_pb_type(cur_pb_type)) {
905	    return;
906	  }
907	
908	  /* Get the physical mode from annotation */
909	  t_mode* physical_mode = vpr_device_annotation.physical_mode(cur_pb_type);
910	
911	  VTR_ASSERT(nullptr != physical_mode);
912	
913	  /* Annotate the circuit model for each interconnect under this physical mode
914	   */
915	  for (t_interconnect* pb_interc : pb_mode_interconnects(physical_mode)) {
916	    /* If the interconnect has been annotated, we skip it */
917	    if (CircuitModelId::INVALID() !=
918	        vpr_device_annotation.interconnect_circuit_model(pb_interc)) {
919	      continue;
920	    }
921	    /* Infer the circuit model type for a given interconnect */
922	    e_circuit_model_type circuit_model_type =
923	      pb_interconnect_require_circuit_model_type(
924	        vpr_device_annotation.interconnect_physical_type(pb_interc));
925	    /* Try to find a default circuit model from the circuit library */
926	    CircuitModelId default_circuit_model =
927	      circuit_lib.default_model(circuit_model_type);
928	    /* Update the annotation if the model id is valid */
929	    if (CircuitModelId::INVALID() == default_circuit_model) {
930	      VTR_LOG_ERROR(
931	        "Unable to infer a circuit model for interconnect '%s' under physical "
932	        "mode '%s' of pb_type '%s'!\n",
933	        pb_interc->name.c_str(), physical_mode->name, cur_pb_type->name);
934	    }
935	    vpr_device_annotation.add_interconnect_circuit_model(pb_interc,
936	                                                         default_circuit_model);
937	    VTR_LOGV(verbose_output,
938	             "Implicitly infer a circuit model '%s' for interconnect '%s' "
939	             "under physical mode '%s' of pb_type '%s'\n",
940	             circuit_lib.model_name(default_circuit_model).c_str(),
941	             pb_interc->name.c_str(), physical_mode->name, cur_pb_type->name);
942	  }
943	
944	  /* Traverse the pb_type children under the physical mode */
945	  for (int ichild = 0; ichild < physical_mode->num_pb_type_children; ++ichild) {
946	    rec_infer_vpr_pb_interconnect_circuit_model_annotation(
947	      &(physical_mode->pb_type_children[ichild]), circuit_lib,
948	      vpr_device_annotation, verbose_output);
949	  }
950	}
951	
952	/********************************************************************
953	 * This function will infer the circuit model for each interconnect
954	 * under a physical mode of a pb_type in VPR pb_type graph without
955	 * OpenFPGA architecture XML
956	 *
957	 * Note:
958	 * This function must be executed AFTER the function
959	 *   build_vpr_physical_pb_mode_explicit_annotation()
960	 *   build_vpr_physical_pb_mode_implicit_annotation()
961	 *******************************************************************/
962	static void link_vpr_pb_interconnect_to_circuit_model_implicit_annotation(
963	  const DeviceContext& vpr_device_ctx, const CircuitLibrary& circuit_lib,
964	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
965	  for (const t_logical_block_type& lb_type :
966	       vpr_device_ctx.logical_block_types) {
967	    /* By pass nullptr for pb_type head */
968	    if (nullptr == lb_type.pb_type) {
969	      continue;
970	    }
971	    rec_infer_vpr_pb_interconnect_circuit_model_annotation(
972	      lb_type.pb_type, circuit_lib, vpr_device_annotation, verbose_output);
973	  }
974	}
