976	/********************************************************************
977	 * This function will bind mode selection bits to a primitive pb_type
978	 * in the vpr_device_annotation
979	 *******************************************************************/
980	static bool link_primitive_pb_type_to_mode_bits(
981	  t_pb_type* primitive_pb_type, const PbTypeAnnotation& pb_type_annotation,
982	  VprDeviceAnnotation& vpr_device_annotation) {
983	  /* Error out if this is not a primitive pb_type */
984	  if (false == is_primitive_pb_type(primitive_pb_type)) {
985	    VTR_LOG_ERROR(
986	      "Mode selection is only applicable to primitive pb_type while pb_type "
987	      "'%s' is not primitve !\n",
988	      primitive_pb_type->name);
989	    return false;
990	  }
991	
992	  /* Update the annotation */
993	  vpr_device_annotation.add_pb_type_mode_bits(
994	    primitive_pb_type, pb_type_annotation.mode_bits(), true);
995	
996	  return true;
997	}
