999	/********************************************************************
1000	 * This function will link
1001	 * - pb_type to mode bits by following
1002	 *   the explicit definition in OpenFPGA architecture XML
1003	 *
1004	 * Note:
1005	 * - This function should be executed only AFTER
1006	 *   the physical mode and physical pb_type annotation is completed
1007	 *   the physical pb_type circuit model annotation is completed
1008	 *******************************************************************/
1009	static void link_vpr_pb_type_to_mode_bits_explicit_annotation(
1010	  const DeviceContext& vpr_device_ctx, const Arch& openfpga_arch,
1011	  VprDeviceAnnotation& vpr_device_annotation, const bool& verbose_output) {
1012	  /* Walk through the pb_type annotation stored in the openfpga arch */
1013	  for (const PbTypeAnnotation& pb_type_annotation :
1014	       openfpga_arch.pb_type_annotations) {
1015	    if (true == pb_type_annotation.mode_bits().empty()) {
1016	      continue;
1017	    }
1018	
1019	    /* Convert the vector of integer to string */
1020	    std::string mode_bits_str;
1021	    for (const char& bit : pb_type_annotation.mode_bits()) {
1022	      mode_bits_str += bit;
1023	    }
1024	
1025	    /* Collect the information about the full hierarchy of physical pb_type to
1026	     * be annotated */
1027	    std::vector<std::string> target_pb_type_names;
1028	    std::vector<std::string> target_pb_mode_names;
1029	
1030	    if (true == pb_type_annotation.is_operating_pb_type()) {
1031	      target_pb_type_names =
1032	        pb_type_annotation.operating_parent_pb_type_names();
1033	      target_pb_type_names.push_back(
1034	        pb_type_annotation.operating_pb_type_name());
1035	      target_pb_mode_names = pb_type_annotation.operating_parent_mode_names();
1036	    }
1037	
1038	    if (true == pb_type_annotation.is_physical_pb_type()) {
1039	      target_pb_type_names = pb_type_annotation.physical_parent_pb_type_names();
1040	      target_pb_type_names.push_back(
1041	        pb_type_annotation.physical_pb_type_name());
1042	      target_pb_mode_names = pb_type_annotation.physical_parent_mode_names();
1043	    }
1044	
1045	    /* We must have at least one pb_type in the list */
1046	    VTR_ASSERT_SAFE(0 < target_pb_type_names.size());
1047	
1048	    /* Pb type information are located at the logic_block_types in the device
1049	     * context of VPR We iterate over the vectors and find the pb_type matches
1050	     * the parent_pb_type_name
1051	     */
1052	    bool link_success = false;
1053	
1054	    for (const t_logical_block_type& lb_type :
1055	         vpr_device_ctx.logical_block_types) {
1056	      /* By pass nullptr for pb_type head */
1057	      if (nullptr == lb_type.pb_type) {
1058	        continue;
1059	      }
1060	      /* Check the name of the top-level pb_type, if it does not match, we can
1061	       * bypass */
1062	      if (target_pb_type_names[0] != std::string(lb_type.pb_type->name)) {
1063	        continue;
1064	      }
1065	      /* Match the name in the top-level, we go further to search the operating
1066	       * as well as physical pb_types in the graph */
1067	      t_pb_type* target_pb_type = try_find_pb_type_with_given_path(
1068	        lb_type.pb_type, target_pb_type_names, target_pb_mode_names);
1069	      if (nullptr == target_pb_type) {
1070	        continue;
1071	      }
1072	
1073	      /* Only try to bind pb_type to circuit model when it is defined by users
1074	       */
1075	      if (true == link_primitive_pb_type_to_mode_bits(target_pb_type,
1076	                                                      pb_type_annotation,
1077	                                                      vpr_device_annotation)) {
1078	        /* Give a message */
1079	        VTR_LOGV(verbose_output,
1080	                 "Bind physical pb_type '%s' to mode selection bits '%s'\n",
1081	                 target_pb_type->name, mode_bits_str.c_str());
1082	
1083	        link_success = true;
1084	        break;
1085	      }
1086	    }
1087	
1088	    if (false == link_success) {
1089	      /* Not found, error out! */
1090	      VTR_LOG_ERROR(
1091	        "Unable to bind pb_type '%s' to mode_selection bits '%s'!\n",
1092	        target_pb_type_names.back().c_str(), mode_bits_str.c_str());
1093	      return;
1094	    }
1095	  }
1096	}
1097	
1098	/********************************************************************
1099	 * Top-level function to link openfpga architecture to VPR, including:
1100	 * - physical pb_type
1101	 * - circuit models for pb_type, pb interconnect
1102	 *******************************************************************/
1103	void annotate_pb_types(const DeviceContext& vpr_device_ctx,
1104	                       const Arch& openfpga_arch,
1105	                       VprDeviceAnnotation& vpr_device_annotation,
1106	                       const bool& verbose_output) {
1107	  /* Annotate physical mode to pb_type in the VPR pb_type graph */
1108	  VTR_LOG("\n");
1109	  VTR_LOG("Building annotation for physical modes in pb_type...");
1110	  VTR_LOGV(verbose_output, "\n");
1111	  build_vpr_physical_pb_mode_explicit_annotation(
1112	    vpr_device_ctx, openfpga_arch, vpr_device_annotation, verbose_output);
1113	
1114	  build_vpr_physical_pb_mode_implicit_annotation(
1115	    vpr_device_ctx, vpr_device_annotation, verbose_output);
1116	  VTR_LOG("Done\n");
1117	
1118	  check_vpr_physical_pb_mode_annotation(
1119	    vpr_device_ctx,
1120	    const_cast<const VprDeviceAnnotation&>(vpr_device_annotation));
1121	
1122	  /* Annotate the physical type for each interconnect under physical modes
1123	   * Must run AFTER physical mode annotation is done and
1124	   * BEFORE inferring the circuit model for interconnect
1125	   */
1126	  VTR_LOG("\n");
1127	  VTR_LOG(
1128	    "Building annotation about physical types for pb_type interconnection...");
1129	  VTR_LOGV(verbose_output, "\n");
1130	  annotate_pb_graph_interconnect_physical_type(
1131	    vpr_device_ctx, vpr_device_annotation, verbose_output);
1132	  VTR_LOG("Done\n");
1133	
1134	  /* Annotate physical pb_types to operating pb_type in the VPR pb_type graph
1135	   * This function will also annotate
1136	   * - pb_type_index_factor
1137	   * - pb_type_index_offset
1138	   * - physical_pin_rotate_offset
1139	   */
1140	  VTR_LOG("\n");
1141	  VTR_LOG("Building annotation between operating and physical pb_types...");
1142	  VTR_LOGV(verbose_output, "\n");
1143	  build_vpr_physical_pb_type_explicit_annotation(
1144	    vpr_device_ctx, openfpga_arch, vpr_device_annotation, verbose_output);
1145	
1146	  build_vpr_physical_pb_type_implicit_annotation(
1147	    vpr_device_ctx, vpr_device_annotation, verbose_output);
1148	  VTR_LOG("Done\n");
1149	
1150	  check_vpr_physical_pb_type_annotation(
1151	    vpr_device_ctx,
1152	    const_cast<const VprDeviceAnnotation&>(vpr_device_annotation));
1153	
1154	  /* Link
1155	   * - physical pb_type to circuit model
1156	   * - interconnect of physical pb_type to circuit model
1157	   */
1158	  VTR_LOG("\n");
1159	  VTR_LOG(
1160	    "Building annotation between physical pb_types and circuit models...");
1161	  VTR_LOGV(verbose_output, "\n");
1162	  link_vpr_pb_type_to_circuit_model_explicit_annotation(
1163	    vpr_device_ctx, openfpga_arch, vpr_device_annotation, verbose_output);
1164	
1165	  link_vpr_pb_interconnect_to_circuit_model_explicit_annotation(
1166	    vpr_device_ctx, openfpga_arch, vpr_device_annotation, verbose_output);
1167	
1168	  link_vpr_pb_interconnect_to_circuit_model_implicit_annotation(
1169	    vpr_device_ctx, openfpga_arch.circuit_lib, vpr_device_annotation,
1170	    verbose_output);
1171	  VTR_LOG("Done\n");
1172	
1173	  check_vpr_pb_type_circuit_model_annotation(
1174	    vpr_device_ctx, openfpga_arch.circuit_lib,
1175	    const_cast<const VprDeviceAnnotation&>(vpr_device_annotation));
1176	
1177	  /* Link physical pb_type to mode_bits */
1178	  VTR_LOG("\n");
1179	  VTR_LOG(
1180	    "Building annotation between physical pb_types and mode selection bits...");
1181	  VTR_LOGV(verbose_output, "\n");
1182	  link_vpr_pb_type_to_mode_bits_explicit_annotation(
1183	    vpr_device_ctx, openfpga_arch, vpr_device_annotation, verbose_output);
1184	  VTR_LOG("Done\n");
1185	
1186	  check_vpr_pb_type_mode_bits_annotation(
1187	    vpr_device_ctx, openfpga_arch.circuit_lib,
1188	    const_cast<const VprDeviceAnnotation&>(vpr_device_annotation));
1189	}
1190	
1191	} /* end namespace openfpga */
